// Fuzzer for apps/lib/kfts_fuzzy_match.h utilities (Qt5-compatible).

#include <cstdint>
#include <cstddef>
#include <string>

#include <fuzzer/FuzzedDataProvider.h>

#include <QString>

// Use the patched header generated by build.sh (QStringView -> QString)
#include "kfts_fuzzy_match_ossfuzz.h"

namespace {

// Safely convert raw bytes to UTF-8 and feed them into QString
static QString toQStringUtf8(const std::string &bytes) {
  if (bytes.empty()) {
    return {};
  }
  return QString::fromUtf8(bytes.data(),
                           static_cast<int>(bytes.size()));
}

}  // namespace

extern "C" int LLVMFuzzerTestOneInput(const uint8_t *data, size_t size) {
  if (size == 0) {
    return 0;
  }

  FuzzedDataProvider fdp(data, size);

  // 1) Generate pattern / text, with length limits so each run stays reasonably fast
  const uint16_t pattern_len =
      fdp.ConsumeIntegralInRange<uint16_t>(0, 64);
  const uint16_t text_len =
      fdp.ConsumeIntegralInRange<uint16_t>(0, 512);

  std::string pattern_bytes =
      fdp.ConsumeBytesAsString(pattern_len);
  std::string text_bytes =
      fdp.ConsumeBytesAsString(text_len);

  // 2) Generate HTML tag / close tag for the display_string helpers
  const uint8_t tag_len =
      fdp.ConsumeIntegralInRange<uint8_t>(0, 8);
  const uint8_t tag_close_len =
      fdp.ConsumeIntegralInRange<uint8_t>(0, 8);

  std::string tag_bytes =
      fdp.ConsumeBytesAsString(tag_len);
  std::string tag_close_bytes =
      fdp.ConsumeBytesAsString(tag_close_len);

  QString pattern = toQStringUtf8(pattern_bytes);
  QString text = toQStringUtf8(text_bytes);
  QString htmlTag = toQStringUtf8(tag_bytes);
  QString htmlTagClose = toQStringUtf8(tag_close_bytes);

  // ---- fuzzy_match_simple / fuzzy_match ----
  if (!pattern.isEmpty()) {
    // Simple match
    (void)kfts::fuzzy_match_simple(pattern, text);

    // Full fuzzy_match (score only)
    int score = 0;
    (void)kfts::fuzzy_match(pattern, text, score);

    // fuzzy_match with matches array
    uint8_t matches[256];
    score = 0;
    (void)kfts::fuzzy_match(pattern, text, score, matches);
  }

  // ---- to_fuzzy_matched_display_string ----
  {
    QString textCopy = text;
    (void)kfts::to_fuzzy_matched_display_string(
        pattern, textCopy, htmlTag, htmlTagClose);
  }

  // ---- to_scored_fuzzy_matched_display_string ----
  {
    QString textCopy = text;
    (void)kfts::to_scored_fuzzy_matched_display_string(
        pattern, textCopy, htmlTag, htmlTagClose);
  }

  // We no longer call get_fuzzy_match_formats to avoid pulling in QtGui / libGL dependencies

  return 0;
}
